const res = $input.first();
if (res.json.error || !res.json.data) {
  throw new Error(`arXiv fetch failed: ${JSON.stringify(res.json)}`);
}
return $input.all();

const feed = $input.first().json.feed;
const entries = Array.isArray(feed.entry) ? feed.entry : [feed.entry].filter(Boolean);
if (!entries.length) throw new Error('No entries found in parsed XML feed');
const papers = entries.map((entry, index) => {
  const title = (Array.isArray(entry.title) ? entry.title[0] : entry.title || '').replace(/\s+/g, ' ').trim();
  const summary = (Array.isArray(entry.summary) ? entry.summary[0] : entry.summary || '').replace(/\s+/g, ' ').trim();
  const published = Array.isArray(entry.published) ? entry.published[0] : entry.published || '';
  const authorList = Array.isArray(entry.author) ? entry.author : [entry.author].filter(Boolean);
  const authors = authorList.map(a => (Array.isArray(a.name) ? a.name[0] : a.name) || '').join(', ');
  const links = Array.isArray(entry.link) ? entry.link : [entry.link].filter(Boolean);
  const absLink = links.find(l => l && l.$ && l.$.type === 'text/html');
  const link = absLink ? absLink.$.href : (links[0] && links[0].$ ? links[0].$.href : '');
  const primaryCat = entry['arxiv:primary_category'];
  const category = primaryCat && primaryCat[0] && primaryCat[0].$ ? primaryCat[0].$.term : 'cs.CL';
  return { index: index + 1, title, authors, summary, link, published, category };
});
return papers.map(p => ({ json: p }));

const papers = $input.first().json.papers;
const paperList = papers.map(p =>
  `### Paper ${p.index}: ${p.title}
**Authors:** ${p.authors}
**Link:** ${p.link}
**Abstract:** ${p.summary}
`
).join('
---
');
const prompt = `You are a research assistant creating a daily paper digest. Below are ${papers.length} recent papers from arXiv. For each paper, provide:

1. **One-line summary** (plain language, what they did and why it matters)
2. **Key contribution** (the novel idea or method)
3. **Relevance score** (High / Medium / Low) for someone working on multilingual RAG systems

After individual summaries, provide a "Today's Highlights" section with the top 3 most relevant papers and a brief explanation of emerging trends.

Format the output as a clean HTML email body with inline styles.

---

${paperList}`;
return [{ json: { prompt, paperCount: papers.length, papers } }];

const response = $input.first().json;
if (response.error) {
  throw new Error(`Groq API error: ${response.error.message || JSON.stringify(response.error)}`);
}
if (!response.choices || !response.choices[0] || !response.choices[0].message || !response.choices[0].message.content) {
  throw new Error(`Unexpected Groq response structure: ${JSON.stringify(response)}`);
}
const content = response.choices[0].message.content;
const paperCount = $('Build LLM Prompt').first().json.paperCount;
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const emailHtml = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family: 'Segoe UI', Arial, sans-serif; max-width: 700px; margin: 0 auto; padding: 20px; color: #333;"><div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); padding: 30px; border-radius: 12px; margin-bottom: 24px;"><h1 style="color: white; margin: 0; font-size: 24px;">Daily Research Digest</h1><p style="color: rgba(255,255,255,0.85); margin: 8px 0 0 0; font-size: 14px;">${today} &middot; ${paperCount} papers reviewed</p></div><div style="background: #fff; border: 1px solid #e2e8f0; border-radius: 8px; padding: 24px;">${content}</div><div style="text-align: center; margin-top: 24px; padding: 16px; color: #94a3b8; font-size: 12px;"><p>Generated by your n8n Paper Digest workflow &middot; Powered by Groq (Llama 3.3)</p><p>Search query: RAG / Retrieval-Augmented Generation (cs.CL, cs.IR)</p></div></body></html>`;
return [{ json: { subject: `Paper Digest: ${paperCount} new papers — ${today}`, htmlBody: emailHtml, paperCount } }];
